) {
}

class FfiConverterTypeAgentResponse: FfiConverterRustBuffer<AgentResponse> {
    public static FfiConverterTypeAgentResponse INSTANCE = new FfiConverterTypeAgentResponse();

    public override AgentResponse Read(BigEndianStream stream) {
        return new AgentResponse(
            @content: FfiConverterString.INSTANCE.Read(stream),
            @reasoning: FfiConverterOptionalString.INSTANCE.Read(stream),
            @inputTokens: FfiConverterUInt64.INSTANCE.Read(stream),
            @outputTokens: FfiConverterUInt64.INSTANCE.Read(stream),
            @totalTokens: FfiConverterUInt64.INSTANCE.Read(stream),
            @contextPercent: FfiConverterFloat.INSTANCE.Read(stream)
        );
    }

    public override int AllocationSize(AgentResponse value) {
        return 0
            + FfiConverterString.INSTANCE.AllocationSize(value.@content)
            + FfiConverterOptionalString.INSTANCE.AllocationSize(value.@reasoning)
            + FfiConverterUInt64.INSTANCE.AllocationSize(value.@inputTokens)
            + FfiConverterUInt64.INSTANCE.AllocationSize(value.@outputTokens)
            + FfiConverterUInt64.INSTANCE.AllocationSize(value.@totalTokens)
            + FfiConverterFloat.INSTANCE.AllocationSize(value.@contextPercent);
    }

    public override void Write(AgentResponse value, BigEndianStream stream) {
            FfiConverterString.INSTANCE.Write(value.@content, stream);
            FfiConverterOptionalString.INSTANCE.Write(value.@reasoning, stream);
            FfiConverterUInt64.INSTANCE.Write(value.@inputTokens, stream);
            FfiConverterUInt64.INSTANCE.Write(value.@outputTokens, stream);
            FfiConverterUInt64.INSTANCE.Write(value.@totalTokens, stream);
            FfiConverterFloat.INSTANCE.Write(value.@contextPercent, stream);
    }
}



