            case AgentException.ParseException:
                stream.WriteInt(2);
                break;
            case AgentException.ConfigException:
                stream.WriteInt(3);
                break;
            case AgentException.InternalException:
                stream.WriteInt(4);
                break;
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeAgentError.Write()", value));
        }
    }
}




